// Each #kernel tells which function to compile; you can have many kernels
#pragma kernel TerrainCSMain

#include "Assets/ComputeShaders/noiseSimplex.cginc"


RWStructuredBuffer<float3> vertices;
RWStructuredBuffer<float3> normals;
RWStructuredBuffer<int3> colors;

float frequency;
float amplitude;
float lacunarity;
float gain;
int octaves;
float maxHeight;
float redistrobution;

int resolution;
float xOffset;
float yOffset;
int size;


float2 noisePos(float2 pos, float freq) { return float2(pos.x * freq, pos.y * freq); }

float fbmcustom(float2 pos, float freq, float amp, float lac, float ga, int oct) {

    float v = 0;
    float ampsum = 0;

    for (int i = 0; i < oct; i++)
        {

            v += (snoise(noisePos(pos, freq)) + 1) * 0.5 * amp;
            ampsum += amp;

            freq *= lac;  // usually 2.0
            amp *= ga;    // usually 0.5
        }

    return pow(v / ampsum, redistrobution);
}

float ridgedNoise(float2 pos, float freq, float amp, float lac, float ga, int oct) {
    float v = 0;
    float maxAmp = 0;
    
    for (int i = 0; i < oct; i++) {
        float n = snoise(noisePos(pos, freq));
        n = abs(n);  // Make it ridged
        n = 1.0 - n; // Invert for peaks
        v += n * n * amp;  // Square for sharper ridges
        maxAmp += amp;
        
        freq *= lac;
        amp *= ga;
    
    }
    
    return v / maxAmp;
}

float2 domainWarp(float2 pos, float warpStrength, float warpFreq) {
    float warp = snoise(noisePos(pos, warpFreq)) * warpStrength;
    return pos + float2(warp, warp);
}
// colorassign now uses a separate biome noise seed and a 20-entry palette
int3 colorassign(float height, float2 pos) {
    // 20-biome palette (R,G,B)
    static const int3 biomeColors[20] = {
        int3(34, 32, 178),   // 0 - deep ocean
        int3(0, 105, 148),   // 1 - shallow ocean
        int3(240, 240, 64),  // 2 - sandy shore
        int3(194, 178, 128), // 3 - beach/sand
        int3(34, 139, 34),   // 4 - grassland
        int3(50, 205, 50),   // 5 - meadow
        int3(34, 85, 34),    // 6 - forest
        int3(0, 100, 0),     // 7 - dense forest
        int3(107, 142, 35),  // 8 - shrubland
        int3(189, 183, 107), // 9 - dry grass
        int3(210, 180, 140), //10 - savanna
        int3(218, 165, 32),  //11 - dry/high plains
        int3(205, 133, 63),  //12 - badlands/rock
        int3(128, 128, 128), //13 - rocky
        int3(160, 160, 160), //14 - scree
        int3(255, 250, 250), //15 - snow
        int3(255, 255, 255), //16 - glacier/ice
        int3(85, 107, 47),   //17 - marsh
        int3(34, 139, 87),   //18 - swamp
        int3(199, 97, 20)    //19 - desert/mesa
    };

    float e = saturate(height / maxHeight);

    // Compute a secondary biome noise using a different seed/offset
    float2 biomeSeedOffset = float2(10000.0, 20000.0);
    float biomeNoise = fbmcustom(pos + biomeSeedOffset, frequency * 0.5, amplitude, lacunarity, gain, octaves) * 0.5 + 0.5;

    // Water handling
    if (e < 0.12)
    {
        if (e < 0.04) return biomeColors[0]; // deep ocean
        return biomeColors[1]; // shallow ocean
    }

    // High elevations force snow
    if (e > 0.82) return biomeColors[15];

    int biomeIndex = (int)floor(saturate(biomeNoise) * 20.0);
    biomeIndex = clamp(biomeIndex, 0, 19);

    return biomeColors[biomeIndex];
}

[numthreads(16,16,1)]
void TerrainCSMain (uint3 id : SV_DispatchThreadID)
{

    uint x = id.x;
    uint y = id.y;
    if (x >= resolution || y >= resolution) return;

    uint idx = x + y * resolution;

    float sizingFactor = (float)size / ((float)resolution - 1.0f);

    float2 noisepos = float2(x * sizingFactor, y * sizingFactor) + float2(xOffset, yOffset);
    float height = fbmcustom(noisepos, frequency, amplitude, lacunarity, gain, octaves) * maxHeight;
    //float height = (fbmcustom(noisepos, frequency, amplitude, lacunarity, gain, octaves) + ridgedNoise(noisepos, frequency, amplitude, lacunarity, gain, octaves)) * maxHeight;

    colors[idx] = colorassign(height, x * sizingFactor, y * sizingFactor);
    vertices[idx] = float3(x * sizingFactor, height, y * sizingFactor);
    normals[idx] = float3(0,1,0);
}

